{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "# Sentinel Data Source Onboarding Assistant\n---\n\nVersion: 1.1"
      },
      "name": "text-WorkbookTitle"
    },
    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [
          {
            "id": "d08e06c0-ba9f-42e4-a518-c417ad30e740",
            "version": "KqlParameterItem/1.0",
            "name": "DefaultSubscription_Internal",
            "type": 1,
            "isRequired": true,
            "query": "where type =~ 'microsoft.operationalinsights/workspaces'\r\n| take 1\r\n| project subscriptionId",
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 86400000
            },
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources"
          },
          {
            "id": "b03d08dc-8541-4e31-947c-30d38d8dd893",
            "version": "KqlParameterItem/1.0",
            "name": "InternalWSs",
            "type": 1,
            "query": "SecurityIncident\r\n| take 1\r\n| parse IncidentUrl with * \"/workspaces/\" Workspace \"/\" *\r\n| project Workspace",
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 0,
            "resourceType": "microsoft.operationalinsights/workspaces"
          },
          {
            "id": "1cd544db-f882-407e-9171-4832195d2c21",
            "version": "KqlParameterItem/1.0",
            "name": "Subscription",
            "type": 6,
            "isRequired": true,
            "query": "resources\r\n| where type =~ 'microsoft.operationalinsights/workspaces'\r\n| distinct subscriptionId\r\n| join kind=inner (resourcecontainers | where type == 'microsoft.resources/subscriptions' | project subscriptionId, subscriptionName = name) on subscriptionId\r\n| project value = strcat('/subscriptions/', subscriptionId), label = subscriptionName, selected = iff(subscriptionId =~ '{DefaultSubscription_Internal}', true, false)\r\n| order by label asc\r\n",
            "typeSettings": {
              "additionalResourceOptions": [],
              "showDefault": false
            },
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources",
            "label": "☁️ Subscription"
          },
          {
            "id": "8176b315-49f6-4fb7-aacb-30b04d59d1e1",
            "version": "KqlParameterItem/1.0",
            "name": "Workspace",
            "type": 5,
            "isRequired": true,
            "query": "let selectedSubscriptionId = tostring(split('{Subscription}', '/')[2]);\r\nlet sentinelWorkspaces = resources\r\n| where type =~ 'microsoft.operationsmanagement/solutions'\r\n| where name startswith 'SecurityInsights('\r\n| where subscriptionId =~ selectedSubscriptionId\r\n| parse name with 'SecurityInsights(' workspaceName ')'\r\n| project id = tostring(properties.workspaceResourceId), label = workspaceName\r\n| distinct id, label;\r\nlet workspaceCount = toscalar(sentinelWorkspaces | count);\r\nsentinelWorkspaces\r\n| project id, label, selected = iff(workspaceCount == 1, true, iff(label =~ '{InternalWSs}', true, false))\r\n| order by label asc",
            "typeSettings": {
              "additionalResourceOptions": []
            },
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources",
            "label": "🗂️ Workspace"
          },
          {
            "id": "3a32bd8f-cfd1-4b20-9f0d-0d66d7aa668f",
            "version": "KqlParameterItem/1.0",
            "name": "WorkspaceEligible",
            "type": 1,
            "query": "let selectedWorkspace = '{Workspace}';\r\nlet hasConMeta = toscalar(_GetWatchlist('Con_Meta') | count);\r\nprint WorkspaceEligible = iff(isempty(selectedWorkspace), 'No', iff(hasConMeta > 0, 'Yes', 'No'))",
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 0,
            "resourceType": "microsoft.operationalinsights/workspaces"
          },
          {
            "id": "a0c2e0eb-d5b6-4700-a394-e70c28b1d04c",
            "version": "KqlParameterItem/1.0",
            "name": "WorkspaceID",
            "type": 1,
            "query": "resources | where type ==\"microsoft.operationalinsights/workspaces\"\r\n| where id has '{Workspace}'\r\n| extend WorkspaceID = trim(\" \",tostring(properties.customerId))\r\n| project WorkspaceID\r\n",
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources"
          },
          {
            "id": "6bb39edf-2812-4cb2-8274-36d3e34e5ac1",
            "version": "KqlParameterItem/1.0",
            "name": "WorkspaceSubscriptionId",
            "type": 1,
            "query": "resources\r\n| where type =~ 'microsoft.operationalinsights/workspaces'\r\n| where tolower(id) == tolower('{Workspace}')\r\n| project WorkspaceSubscriptionId = subscriptionId",
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources"
          },
          {
            "id": "36bc67cb-aef9-4d6f-b830-6642326f3712",
            "version": "KqlParameterItem/1.0",
            "name": "WorkspaceResourceGroup",
            "type": 1,
            "query": "resources\r\n| where type =~ 'microsoft.operationalinsights/workspaces'\r\n| where tolower(id) == tolower('{Workspace}')\r\n| project WorkspaceResourceGroup = resourceGroup",
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 259200000
            },
            "queryType": 1,
            "resourceType": "microsoft.resourcegraph/resources"
          },
          {
            "id": "0fc73ced-c849-4b09-9dfc-805ecb089433",
            "version": "KqlParameterItem/1.0",
            "name": "Help",
            "label": "📖 Help",
            "type": 10,
            "isRequired": true,
            "typeSettings": {
              "additionalResourceOptions": []
            },
            "jsonData": "[{ \"value\": \"Yes\", \"label\": \"Yes\"},\r\n {\"value\": \"No\", \"label\": \"No\", \"selected\":true }]",
            "timeContext": {
              "durationMs": 86400000
            },
            "value": "No"
          },
          {
            "id": "03655c59-0806-45b8-8b2e-2ae8e8449c32",
            "version": "KqlParameterItem/1.0",
            "name": "Tab",
            "type": 1,
            "isRequired": true,
            "isGlobal": true,
            "isHiddenWhenLocked": true,
            "timeContext": {
              "durationMs": 259200000
            },
            "value": "1"
          }
        ],
        "style": "above",
        "queryType": 1,
        "resourceType": "microsoft.resourcegraph/resources"
      },
      "name": "params-Global"
    },
    {
      "type": 1,
      "content": {
        "json": "### Introduction\r\n\r\nThis workbook is designed to catalog all currently available and installed data connectors in Microsoft Sentinel, providing security analysts with a centralized, searchable inventory. It facilitates quick identification of specific connectors and offers actionable recommendations for alternative onboarding approaches when a direct connector is unavailable.\r\n\r\nThese insights are categorized into three tabs: **Available Data Connectors**, **Alternative Ingestion Methods**, and **Installed Connectors & Coverage**.\r\n\r\n**Required data sources:**\r\n\r\nTo make this workbook work properly it is necessary to have auditing and health monitoring data.<br>\r\nFollow the instructions on how to [Turn on auditing and health monitoring for Microsoft Sentinel](https://learn.microsoft.com/azure/sentinel/enable-monitoring).",
        "style": "info"
      },
      "conditionalVisibility": {
        "parameterName": "Help",
        "comparison": "isEqualTo",
        "value": "Yes"
      },
      "name": "text-info"
    },
    {
      "type": 11,
      "content": {
        "version": "LinkItem/1.0",
        "style": "tabs",
        "tabStyle": "bigger",
        "links": [
          {
            "id": "78d81c4a-0748-46dc-861f-fcf93b8f6aa0",
            "cellValue": "Tab",
            "linkTarget": "parameter",
            "linkLabel": "Available Data Connectors",
            "subTarget": "1",
            "style": "link",
            "tabWidth": "280px"
          },
          {
            "id": "89698cb9-ac70-4fa7-aef7-342524c147b7",
            "cellValue": "Tab",
            "linkTarget": "parameter",
            "linkLabel": "Alternative Ingestion Methods",
            "subTarget": "2",
            "style": "link",
            "tabWidth": "280px"
          },
          {
            "id": "c3a1f2d4-5e6b-7890-abcd-ef1234567890",
            "cellValue": "Tab",
            "linkTarget": "parameter",
            "linkLabel": "Installed Connectors & Coverage",
            "subTarget": "3",
            "style": "link",
            "tabWidth": "280px"
          }
        ]
      },
      "name": "links-TabSwitcher",
      "styleSettings": {
        "padding": "0"
      }
    },
    {
      "type": 1,
      "content": {
        "json": "### Workspace Not Ready\r\n\r\nThe selected workspace is not eligible yet for this workbook view.\r\n\r\nRequired:\r\n- Microsoft Sentinel must be enabled on the workspace\r\n- Watchlist Con_Meta must exist\r\n\r\nNext steps:\r\n1. Select a Sentinel-enabled workspace from the picker\r\n2. If this is a fresh deployment, run Refresh Connector Catalog once to initialize data\r\n3. Reload the workbook",
        "style": "warning"
      },
      "conditionalVisibility": {
        "parameterName": "WorkspaceEligible",
        "comparison": "isNotEqualTo",
        "value": "Yes"
      },
      "name": "text-WorkspaceEligibilityGuard"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "items": [
          {
            "type": 12,
            "content": {
              "version": "NotebookGroup/1.0",
              "groupType": "editable",
              "items": [
                {
                  "type": 1,
                  "content": {
                    "json": "\r\n---\r\n## Search for an available Connector:\r\n---",
                    "style": "info"
                  },
                  "name": "text-SearchHeader"
                },
                {
                  "type": 9,
                  "content": {
                    "version": "KqlParameterItem/1.0",
                    "parameters": [
                      {
                        "id": "1b27f605-cc27-44bb-8503-9732ca38daa4",
                        "version": "KqlParameterItem/1.0",
                        "name": "SelectedConnector",
                        "type": 2,
                        "query": "_GetWatchlist('Con')\r\n| project ['Connector Name']\r\n| order by ['Connector Name'] asc",
                        "typeSettings": {
                          "additionalResourceOptions": [],
                          "showDefault": false
                        },
                        "timeContext": {
                          "durationMs": 86400000
                        },
                        "queryType": 0,
                        "resourceType": "microsoft.operationalinsights/workspaces",
                        "label": "Connector Name",
                        "value": null
                      }
                    ],
                    "style": "above",
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces"
                  },
                  "name": "param-ConnectorSearch"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "let connector = '{SelectedConnector}';\r\n_GetWatchlist('Con')\r\n| where ['Connector Name'] == connector\r\n| project ['Connector Name'],['Vendor'],['Method'],['Domain'],['Status'],['Table Count']\r\n",
                    "size": 4,
                    "timeContext": {
                      "durationMs": 86400000
                    },
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "table",
                    "sortBy": [],
                    "tileSettings": {
                      "showBorder": false
                    },
                    "graphSettings": {
                      "type": 0
                    },
                    "mapSettings": {
                      "locInfo": "LatLong"
                    }
                  },
                  "conditionalVisibility": {
                    "parameterName": "SelectedConnector",
                    "comparison": "isNotEqualTo"
                  },
                  "name": "query-SearchResults"
                },
                {
                  "type": 1,
                  "content": {
                    "json": "**Connector Description:**"
                  },
                  "conditionalVisibility": {
                    "parameterName": "SelectedConnector",
                    "comparison": "isNotEqualTo"
                  },
                  "name": "text-DescriptionLabel"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "let connector = '{SelectedConnector}';\r\n_GetWatchlist('Con') | where ['Connector Name'] == connector | project ['Connector Description'] | take 1",
                    "size": 4,
                    "timeContext": {
                      "durationMs": 86400000
                    },
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "card"
                  },
                  "name": "query-ConnectorDescription"
                },
                {
                  "type": 11,
                  "content": {
                    "version": "LinkItem/1.0",
                    "style": "list",
                    "links": [
                      {
                        "id": "bce5861c-142f-4d19-bc02-926c9aa846ac",
                        "cellValue": "",
                        "linkTarget": "CopilotNudge",
                        "linkLabel": "Ask Copilot in Azure for more Information",
                        "style": "primary",
                        "copilotNudgeActionSettings": {
                          "nudgeContent": "Create a short description using  {SelectedConnector} as the selected sentinel data connector name and only official Microsoft or vendor sources related to this connector.\n\nInclude:\n1) Overview & Use Cases\n2) Prerequisites\n3) Enablement Steps\n4) Data Schema\n5) References\n\nUse numbered headings, bullets for lists, code blocks for CLI/KQL, omit unknowns, cite official sources."
                        }
                      }
                    ]
                  },
                  "conditionalVisibility": {
                    "parameterName": "SelectedConnector",
                    "comparison": "isNotEqualTo"
                  },
                  "name": "link-CopilotNudge"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "_GetWatchlist('Con_Meta')\r\n| extend RefreshTime = todatetime(Timestamp)\r\n| summarize arg_max(RefreshTime, *)\r\n| project Status = case(\r\n    Result == 'Success', strcat('✅ Updated ', format_datetime(RefreshTime, 'yyyy-MM-dd HH:mm:ss'), ' (', tostring(ActiveCount), ' active)'),\r\n    Result == 'Pending', strcat('⏳ Not refreshed yet (seeded ', format_datetime(RefreshTime, 'yyyy-MM-dd HH:mm:ss'), ')'),\r\n    Result == 'Failed', strcat('❌ Last refresh failed at ', format_datetime(RefreshTime, 'yyyy-MM-dd HH:mm:ss'), iff(isnotempty(tostring(FailureStage)), strcat(' [', tostring(FailureStage), ']'), ''), iff(isnotempty(tostring(ErrorSummary)), strcat(' - ', tostring(ErrorSummary)), '')),\r\n    strcat('⚠️ Last refresh: ', tostring(Result), ' at ', format_datetime(RefreshTime, 'yyyy-MM-dd HH:mm:ss'))\r\n)",
                    "size": 4,
                    "title": "Connector Catalog Status",
                    "timeContext": {
                      "durationMs": 86400000
                    },
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "card"
                  },
                  "customWidth": "70",
                  "name": "query-CatalogStatus"
                },
                {
                  "type": 11,
                  "content": {
                    "version": "LinkItem/1.0",
                    "style": "paragraph",
                    "links": [
                      {
                        "id": "a7b8c9d0-e1f2-3456-abcd-789012345678",
                        "linkTarget": "ArmAction",
                        "linkLabel": "🔄 Refresh Connector Catalog",
                        "style": "primary",
                        "armActionContext": {
                          "path": "/subscriptions/{WorkspaceSubscriptionId}/resourceGroups/{WorkspaceResourceGroup}/providers/Microsoft.Logic/workflows/la-watchlist-refresh/triggers/Recurrence/run?api-version=2016-06-01",
                          "httpMethod": "POST",
                          "title": "Refresh Connector Catalog",
                          "description": "This will trigger the Logic App to refresh the connector watchlist from GitHub. The process takes about 1–2 minutes. Reload the workbook afterward to see updated data.",
                          "actionName": "RunLogicApp",
                          "runLabel": "Refresh"
                        }
                      }
                    ]
                  },
                  "customWidth": "30",
                  "name": "link-RefreshCatalog"
                },
                {
                  "type": 1,
                  "content": {
                    "json": "ℹ️ Default behavior: **Refresh Connector Catalog** triggers the Logic App in the selected workspace's resource group.\r\n\r\nAlternative: if your Logic App is hosted in a different resource group, choose it below and use **Refresh (Alternative Target)**.",
                    "style": "info"
                  },
                  "name": "text-RefreshBehaviorNote"
                },
                {
                  "type": 9,
                  "content": {
                    "version": "KqlParameterItem/1.0",
                    "parameters": [
                      {
                        "id": "9abf8a90-f540-4ea8-a6a3-d2f19ef93c85",
                        "version": "KqlParameterItem/1.0",
                        "name": "RefreshWorkflowOverride",
                        "type": 5,
                        "query": "resources\r\n| where type =~ 'microsoft.logic/workflows'\r\n| where name =~ 'la-watchlist-refresh'\r\n| project id, label = strcat(name, ' (', resourceGroup, ')'), selected = iff(tolower(subscriptionId) == tolower('{WorkspaceSubscriptionId}') and tolower(resourceGroup) == tolower('{WorkspaceResourceGroup}'), true, false)",
                        "typeSettings": {
                          "additionalResourceOptions": [],
                          "showDefault": false
                        },
                        "timeContext": {
                          "durationMs": 259200000
                        },
                        "queryType": 1,
                        "resourceType": "microsoft.resourcegraph/resources",
                        "label": "Alternative refresh target (Logic App)"
                      }
                    ],
                    "style": "above",
                    "queryType": 1,
                    "resourceType": "microsoft.resourcegraph/resources"
                  },
                  "name": "param-RefreshWorkflowOverride"
                },
                {
                  "type": 11,
                  "content": {
                    "version": "LinkItem/1.0",
                    "style": "paragraph",
                    "links": [
                      {
                        "id": "5de89ed9-73b6-438a-a330-f55332ec132d",
                        "linkTarget": "ArmAction",
                        "linkLabel": "🔄 Refresh (Alternative Target)",
                        "style": "primary",
                        "armActionContext": {
                          "path": "{RefreshWorkflowOverride}/triggers/Recurrence/run?api-version=2016-06-01",
                          "httpMethod": "POST",
                          "title": "Refresh Connector Catalog (Alternative Target)",
                          "description": "Use this option when the Logic App is in a different resource group than the selected workspace.",
                          "actionName": "RunLogicAppAlt",
                          "runLabel": "Refresh"
                        }
                      }
                    ]
                  },
                  "conditionalVisibility": {
                    "parameterName": "RefreshWorkflowOverride",
                    "comparison": "isNotEqualTo"
                  },
                  "name": "link-RefreshCatalogAlternative"
                },
                {
                  "type": 1,
                  "content": {
                    "json": "---\r\n## List of all available Connectors:\r\n---",
                    "style": "info"
                  },
                  "name": "text-AllConnectorsHeader"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "_GetWatchlist('Con') | summarize dataconnectorcount=count() by ['Vendor']\r\n| sort by dataconnectorcount",
                    "size": 3,
                    "title": "Connectors by Publisher",
                    "timeContext": {
                      "durationMs": 86400000
                    },
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "piechart",
                    "graphSettings": {
                      "type": 0,
                      "topContent": {
                        "columnMatch": "Vendor",
                        "formatter": 1
                      },
                      "centerContent": {
                        "columnMatch": "dataconnectorcount",
                        "formatter": 1,
                        "numberFormat": {
                          "unit": 17,
                          "options": {
                            "maximumSignificantDigits": 3,
                            "maximumFractionDigits": 2
                          }
                        }
                      }
                    },
                    "mapSettings": {
                      "locInfo": "LatLong",
                      "sizeSettings": "dataconnectorcount",
                      "sizeAggregation": "Sum",
                      "legendMetric": "dataconnectorcount",
                      "legendAggregation": "Sum",
                      "itemColorSettings": {
                        "type": "heatmap",
                        "colorAggregation": "Sum",
                        "nodeColorField": "dataconnectorcount",
                        "heatmapPalette": "greenRed"
                      }
                    }
                  },
                  "customWidth": "50",
                  "name": "query-VendorPieChart"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "_GetWatchlist('Con') | where Status == 'Active' | summarize count() by Method = tostring(['Method'])\r\n| sort by count_",
                    "size": 3,
                    "title": "Active Connectors by Method",
                    "timeContext": {
                      "durationMs": 86400000
                    },
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "visualization": "piechart"
                  },
                  "customWidth": "50",
                  "name": "query-MethodPieChart"
                },
                {
                  "type": 9,
                  "content": {
                    "version": "KqlParameterItem/1.0",
                    "parameters": [
                      {
                        "id": "b2c3d4e5-f6a7-8901-bcde-f01234567890",
                        "version": "KqlParameterItem/1.0",
                        "name": "ConnectorFilter",
                        "label": "Show",
                        "type": 10,
                        "isRequired": true,
                        "typeSettings": {
                          "additionalResourceOptions": [],
                          "showDefault": false
                        },
                        "jsonData": "[{ \"value\": \"All\", \"label\": \"All\", \"selected\": true },\r\n{ \"value\": \"FirstParty\", \"label\": \"🔷 First Party (Microsoft)\" },\r\n{ \"value\": \"ThirdParty\", \"label\": \"🔶 Third Party\" },\r\n{ \"value\": \"Deprecated\", \"label\": \"🚫 Deprecated\" }]",
                        "timeContext": {
                          "durationMs": 86400000
                        }
                      }
                    ],
                    "style": "above",
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces"
                  },
                  "name": "param-ConnectorFilter"
                },
                {
                  "type": 3,
                  "content": {
                    "version": "KqlItem/1.0",
                    "query": "_GetWatchlist('Con')\r\n| project ['Connector Name'], ['Vendor'], ['Method'], ['Domain'], ['Status']\r\n| where '{ConnectorFilter}' == 'All'\r\n    or ('{ConnectorFilter}' == 'Deprecated' and Status == 'Deprecated')\r\n    or ('{ConnectorFilter}' == 'FirstParty' and Status != 'Deprecated' and Vendor has 'Microsoft')\r\n    or ('{ConnectorFilter}' == 'ThirdParty' and Status != 'Deprecated' and not(Vendor has 'Microsoft'))",
                    "size": 0,
                    "timeContext": {
                      "durationMs": 86400000
                    },
                    "queryType": 0,
                    "resourceType": "microsoft.operationalinsights/workspaces",
                    "gridSettings": {
                      "rowLimit": 10000,
                      "formatters": [
                        {
                          "columnMatch": "Status",
                          "formatter": 18,
                          "formatOptions": {
                            "thresholdsOptions": "icons",
                            "thresholdsGrid": [
                              {
                                "operator": "contains",
                                "thresholdValue": "Deprecated",
                                "representation": "4",
                                "text": "{0}{1}"
                              },
                              {
                                "operator": "Default",
                                "thresholdValue": "",
                                "representation": "success",
                                "text": "{0}{1}"
                              }
                            ]
                          }
                        }
                      ]
                    }
                  },
                  "name": "query-AllConnectorsGrid"
                }
              ]
            },
            "customWidth": "70",
            "name": "group-Tab1-Main"
          },
          {
            "type": 12,
            "content": {
              "version": "NotebookGroup/1.0",
              "groupType": "editable",
              "items": [
                {
                  "type": 1,
                  "content": {
                    "json": "### Next Steps\r\nThe official Microsoft Learn documentation provides a comprehensive list of available data connectors, including detailed guidance for onboarding each connector.\r\n\r\n🔗: [Find your Sentinel data connector](https://learn.microsoft.com/en-us/azure/sentinel/data-connectors-reference#sentinel-data-connectors)\r\n\r\nTo streamline your workflow and bypass further extensive research, proceed directly to the installation of the identified data connector through the Microsoft Sentinel Content Hub 👇.",
                    "style": "upsell"
                  },
                  "name": "text-NextStepsInfo"
                },
                {
                  "type": 11,
                  "content": {
                    "version": "LinkItem/1.0",
                    "style": "paragraph",
                    "links": [
                      {
                        "id": "3f4eaa0c-38e6-40d3-8dc8-bc5281a1908c",
                        "linkTarget": "OpenBlade",
                        "linkLabel": "Open Content Hub",
