1 connector installed (1/', tostring(Total), ' available)'),\r\n    Action = 'Add a second connector to eliminate single point of failure';\r\nlet healthIssues = SentinelHealth\r\n| where TimeGenerated > ago(7d)\r\n| where SentinelResourceType == \"Data connector\"\r\n| where Status in (\"Failure\", \"Warning\")\r\n| summarize Count = count(), LastSeen = max(TimeGenerated) by SentinelResourceName, Status\r\n| project\r\n    Priority = iff(Status == \"Failure\", 'High', 'Medium'),\r\n    Category = iff(Status == \"Failure\", 'Connector Failure', 'Connector Warning'),\r\n    Finding = strcat(SentinelResourceName, ' — ', tostring(Count), ' ', tolower(Status), ' event(s), last seen ', format_datetime(LastSeen, 'yyyy-MM-dd HH:mm')),\r\n    Action = iff(Status == \"Failure\", 'Investigate connector configuration and data source connectivity', 'Open Connector Health Details and review Recent Failures & Warnings');\r\nlet staleConnectors = SentinelHealth\r\n| where TimeGenerated > ago(7d)\r\n| where SentinelResourceType == \"Data connector\"\r\n| summarize LastEvent = max(TimeGenerated) by SentinelResourceName\r\n| where LastEvent < ago(3d)\r\n| project\r\n    Priority = 'Medium',\r\n    Category = 'Stale Data',\r\n    Finding = strcat(SentinelResourceName, ' — last health event ', format_datetime(LastEvent, 'yyyy-MM-dd HH:mm'), ' (3+ days ago)'),\r\n    Action = 'Verify the data source is still active and sending data';\r\nunion coverageGaps, healthIssues, minimalCoverage, staleConnectors\r\n| sort by Priority asc, Category asc",
